<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand</title>
<style>
  * { margin:0; padding:0; box-sizing:border-box; }
  body {
    background:#1a1a2e; color:#eee; font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;
    display:flex; flex-direction:column; align-items:center; min-height:100vh; padding:20px;
  }
  h1 { margin-bottom:14px; font-size:26px; color:#f4d03f; letter-spacing:1px; }
  .controls { display:flex; gap:8px; margin-bottom:14px; flex-wrap:wrap; justify-content:center; }
  button {
    padding:9px 17px; border:none; border-radius:7px; cursor:pointer; font-size:13.5px;
    font-weight:bold; transition:all .2s ease; color:#fff;
  }
  button:hover { transform:translateY(-2px); box-shadow:0 4px 12px rgba(0,0,0,.35); }
  #mat-sand   { background:#f4d03f; }
  #mat-water  { background:#4fc3f7; }
  #mat-wall   { background:#95a5a6; }
  #mat-acid   { background:#ff6b6b; }
  #mat-empty  { background:#2d2d44; border:1px solid #555; color:#ccc; }
  #clear      { background:#e74c3c; margin-left:8px; }
  canvas {
    display:block; border-radius:10px; cursor:crosshair;
    box-shadow:0 0 24px rgba(0,0,0,.5);
  }
  .info { margin-top:12px; font-size:12.5px; color:#7a7a9e; }
</style>
</head>
<body>

<h1>Falling Sand</h1>

<div class="controls">
  <button id="mat-sand"   onclick="selectMaterial('sand')">Sand</button>
  <button id="mat-water"  onclick="selectMaterial('water')">Water</button>
  <button id="mat-wall"   onclick="selectMaterial('wall')">Wall</button>
  <button id="mat-acid"   onclick="selectMaterial('acid')">Acid</button>
  <button id="mat-empty"  onclick="selectMaterial('empty')">Eraser</button>
  <button id="clear">Clear All</button>
</div>

<canvas id="sand"></canvas>

<div class="info">Drag to paint · Click buttons to select material · Walls erode with acid</div>

<script>
/* ── Grid & Materials ─────────────────────────────────────── */
const W = 80, H = 80;
let grid = [];
let selMat = 'sand';
let painting = false;

const EMPTY='empty', SAND='sand', WATER='water', WALL='wall', ACID='acid';

function initGrid(){
  grid=[];
  for(let x=0;x<W;x++) grid[x]=new Array(H).fill(EMPTY);
}

function setCell(x,y,m){ if(x>=0&&x<W&&y>=0&&y<H) grid[x][y]=m; }
function getCell(x,y){ return (x>=0&&x<W&&y>=0&&y<H)?grid[x][y]:EMPTY; }

/* ── Simulation ───────────────────────────────────────────── */
function tick(){
  // Phase 1 – move particles bottom-up so each particle moves ≤1 cell/step
  for(let y=H-2;y>=0;y--){
    for(let x=0;x<W;x++){
      let c = grid[x][y];
      if(c===SAND)        moveSand(x,y);
      else if(c===WATER||c===ACID) moveLiquid(c,x,y);
    }
  }
  // Phase 2 – acid dissolves adjacent sand/wall (below & beside)
  for(let y=0;y<H;y++){
    for(let x=0;x<W;x++){
      if(grid[x][y]===ACID){ dissolveNear(x,y); }
    }
  }
}

function moveSand(x,y){
  let b=getCell(x,y+1);
  if(b===EMPTY||b===WATER||b===ACID){ swap(x,y,x,y+1); return; }
  // diagonal slide
  let dir=Math.random()<.5?-1:1;
  if(dir===-1&&x>0){
    let l=getCell(x-1,y+1);
    if(l===EMPTY){ swap(x,y,x-1,y+1); return; }
  }
  if(dir===1&&x<W-1){
    let r=getCell(x+1,y+1);
    if(r===EMPTY){ swap(x,y,x+1,y+1); return; }
  }
}

function moveLiquid(type,x,y){
  let b=getCell(x,y+1);
  if(b===EMPTY){ swap(x,y,x,y+1); return; }
  // spread horizontally
  let dir=Math.random()<.5?-1:1;
  if(dir===-1&&x>0){
    let l=getCell(x-1,y);
    if(l===EMPTY){ swap(x,y,x-1,y); return; }
  }
  if(dir===1&&x<W-1){
    let r=getCell(x+1,y);
    if(r===EMPTY){ swap(x,y,x+1,y); return; }
  }
}

function swap(x1,y1,x2,y2){
  let t=grid[x1][y1]; grid[x1][y1]=grid[x2][y2]; grid[x2][y2]=t;
}

function dissolveNear(ax,ay){
  const D=[[0,1],[1,0],[-1,0]]; // down, right, left
  for(let d of D){
    let nx=ax+d[0],ny=ay+d[1];
    if(nx>=0&&nx<W&&ny>=0&&ny<H){
      if(grid[nx][ny]===SAND||grid[nx][ny]===WALL) grid[nx][ny]=EMPTY;
    }
  }
}

/* ── Public API on window.sim ─────────────────────────────── */
window.sim = {
  w: W, h: H,
  tick(n){ for(let i=0;i<n;i++) tick(); },
  get(x,y){ return getCell(x,y); },
  set(x,y,m){ setCell(x,y,m); draw(); },
  clear(){ initGrid(); draw(); }
};

/* ── Rendering ────────────────────────────────────────────── */
const canvas=document.getElementById('sand');
const ctx=canvas.getContext('2d');
canvas.width=W*5; canvas.height=H*5; // exactly 400×400 CSS px

const COLORS={ SAND:'#f4d03f', WATER:'#4fc3f7', WALL:'#95a5a6', ACID:'#ff6b6b' };
const BG='#1a1a2e';

function draw(){
  ctx.fillStyle=BG; ctx.fillRect(0,0,canvas.width,canvas.height);
  for(let y=0;y<H;y++){
    for(let x=0;x<W;x++){
      let c=grid[x][y];
      if(c===EMPTY) continue;
      ctx.fillStyle=COLORS[c]||'#fff';
      ctx.fillRect(x*5,y*5,5,5);
    }
  }
}

/* ── Mouse Painting ───────────────────────────────────────── */
canvas.addEventListener('mousedown',e=>{ painting=true; paintAt(e.offsetX,e.offsetY); });
canvas.addEventListener('mousemove',e=>{ if(painting) paintAt(e.offsetX,e.offsetY); });
canvas.addEventListener('mouseup',()=>painting=false);

function paintAt(px,py){
  let x=Math.floor(px/5), y=Math.floor(py/5);
  if(x>=0&&x<W&&y>=0&&y<H){
    setCell(x,y,selMat==='empty'?EMPTY:selMat);
  }
}

/* ── UI Wiring ────────────────────────────────────────────── */
function selectMaterial(m){ selMat=m; highlightBtn(m); }
function highlightBtn(m){
  document.querySelectorAll('.controls button').forEach(b=>b.style.border='none');
  const map={sand:'#mat-sand',water:'#mat-water',wall:'#mat-wall',acid:'#mat-acid',empty:'#mat-empty'};
  document.getElementById(map[m]).style.border='2px solid #fff';
}

document.getElementById('clear').addEventListener('click',()=>{ initGrid(); draw(); });

/* ── Boot ─────────────────────────────────────────────────── */
initGrid(); draw();
function loop(){ tick(); draw(); requestAnimationFrame(loop); }
loop();
</script>
</body>
</html>
